/**
 * Connect to a EerieService server over WebSocket.
 * @param url - WebSocket URL (e.g., "ws://localhost:9000")
 * @returns A connected EerieServiceClient instance
 */
export async function connectEerieService(
  url: string,
  options: SessionTransportOptions = {},
): Promise<EerieServiceClient> {
  const established = await session.initiator(wsConnector(url), { ...options, metadata: voxServiceMetadata("EerieService") });
  return new EerieServiceClient(established.rootConnection().caller());
}

